import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import ProblemSection from './components/ProblemSection';
import FrameworkSection from './components/FrameworkSection';
import StatsSection from './components/StatsSection';
import ServicesSection from './components/ServicesSection';
import ComparisonSection from './components/ComparisonSection';
import ContactSection from './components/ContactSection';
import Footer from './components/Footer';

const App: React.FC = () => {
  return (
    <div className="bg-white text-gray-900 font-sans selection:bg-primary/20">
      <Navbar />
      <main>
        <Hero />
        <ProblemSection />
        <FrameworkSection />
        <StatsSection />
        <ServicesSection />
        <ComparisonSection />
        <ContactSection />
      </main>
      <Footer />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Menu, X } from 'lucide-react';

const Navbar: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Market Challenges', href: '#problem' },
    { name: 'Our Framework', href: '#framework' },
    { name: 'Services', href: '#services' },
  ];

  return (
    <nav
      className={`fixed w-full z-50 transition-all duration-300 ${
        isScrolled
          ? 'bg-white/95 backdrop-blur-md shadow-sm py-3'
          : 'bg-transparent py-5'
      }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          {/* Logo */}
          <div className="flex-shrink-0 flex items-center cursor-pointer">
            <img 
              src="https://i.ibb.co/HTC9hMQm/logo.png" 
              alt="Mahana Logo" 
              className="h-10 w-auto"
            />
            <span className="ml-3 font-display font-bold text-2xl tracking-wide uppercase text-secondary">
              Mahana
            </span>
          </div>

          {/* Desktop Nav */}
          <div className="hidden md:flex items-center space-x-8">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                className="text-sm font-medium text-gray-600 hover:text-secondary transition-colors"
              >
                {link.name}
              </a>
            ))}
            <a
              href="#contact"
              className="px-5 py-2.5 rounded-md bg-secondary text-white hover:bg-opacity-90 transition-all font-medium text-sm shadow-md hover:shadow-lg transform hover:-translate-y-0.5"
            >
              Consultation
            </a>
          </div>

          {/* Mobile Menu Button */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="text-secondary hover:text-primary transition-colors"
            >
              {isMobileMenuOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="md:hidden bg-white border-t border-gray-100 absolute w-full shadow-lg">
          <div className="px-4 pt-2 pb-6 space-y-1">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                className="block px-3 py-3 text-base font-medium text-gray-700 hover:text-primary hover:bg-gray-50 rounded-md"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                {link.name}
              </a>
            ))}
            <a
              href="#contact"
              className="block mt-4 text-center px-4 py-3 bg-secondary text-white rounded-md font-bold"
              onClick={() => setIsMobileMenuOpen(false)}
            >
              Consultation
            </a>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React from 'react';
import { Languages, Search, ShieldAlert } from 'lucide-react';

const ProblemSection: React.FC = () => {
  const problems = [
    {
      icon: <Languages size={32} />,
      title: "Direct Translation Fails",
      description: "Japanese consumers distrust direct translations. Nuance, honorifics (Keigo), and context are critical for building brand authority.",
      colorClass: "bg-blue-100 text-secondary",
    },
    {
      icon: <Search size={32} />,
      title: "Unique Keyword Behavior",
      description: "Japanese users search differently. They use unique phrasing and combinations that Western keyword tools often miss completely.",
      colorClass: "bg-orange-100 text-primary",
    },
    {
      icon: <ShieldAlert size={32} />,
      title: "Risk-Averse Culture",
      description: "Trust is the currency of Japan. Without specific trust signals and detailed information, conversion rates remain stagnant.",
      colorClass: "bg-purple-100 text-purple-700",
    },
  ];

  return (
    <section id="problem" className="py-24 bg-white border-t border-gray-100">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center max-w-3xl mx-auto mb-16">
          <h2 className="text-3xl md:text-4xl font-display font-bold text-secondary mb-4">
            Why Most Foreign Companies Struggle in Japan
          </h2>
          <p className="text-gray-500 text-lg">
            It's rarely about the product quality. It's about a fundamental disconnect in communication.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {problems.map((prob, idx) => (
            <div
              key={idx}
              className="p-8 rounded-xl bg-gray-50 border border-gray-100 hover:shadow-xl hover:bg-white transition-all duration-300 group"
            >
              <div className={`w-14 h-14 ${prob.colorClass} rounded-2xl flex items-center justify-center mb-6 transition-transform group-hover:scale-110`}>
                {prob.icon}
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-3">{prob.title}</h3>
              <p className="text-gray-600 text-sm leading-relaxed">
                {prob.description}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default ProblemSection;

